"""
AEON Phylactery — Append-only identity chain.

The Phylactery maintains a hash-chained identity canon. Each commit
contains a doctrine update and links to its parent via SHA-256.
The HEAD hash is the agent's current identity vector.

Spec: AEON_PHYLACTERY
"""

from __future__ import annotations

import json
import hashlib
import time
from dataclasses import dataclass, field
from pathlib import Path


@dataclass
class PhylacteryCommit:
    content: str
    parent_hash: str
    timestamp: float = field(default_factory=time.time)
    hash: str = ""

    def __post_init__(self):
        if not self.hash:
            self.hash = hashlib.sha256(
                (self.parent_hash + self.content).encode()
            ).hexdigest()


class Phylactery:
    """Append-only identity chain with tamper detection."""

    def __init__(self, genesis_doctrine: str):
        genesis = PhylacteryCommit(content=genesis_doctrine, parent_hash="")
        self.chain: list[PhylacteryCommit] = [genesis]

    def to_dict(self) -> dict:
        return {
            "chain": [
                {
                    "content": commit.content,
                    "parent_hash": commit.parent_hash,
                    "timestamp": commit.timestamp,
                    "hash": commit.hash,
                }
                for commit in self.chain
            ]
        }

    @classmethod
    def from_dict(cls, payload: dict) -> "Phylactery":
        chain_data = payload.get("chain") or []
        if not chain_data:
            raise ValueError("Phylactery payload must include a non-empty chain.")

        genesis = chain_data[0]
        inst = cls(genesis.get("content", ""))
        inst.chain = []
        for item in chain_data:
            commit = PhylacteryCommit(
                content=item["content"],
                parent_hash=item["parent_hash"],
                timestamp=item.get("timestamp", time.time()),
                hash=item.get("hash", ""),
            )
            if commit.hash != item.get("hash", commit.hash):
                raise ValueError("Phylactery commit hash mismatch during load.")
            inst.chain.append(commit)
        if not inst.verify_chain():
            raise ValueError("Loaded Phylactery chain failed verification.")
        return inst

    def save(self, path: str | Path) -> None:
        path = Path(path)
        path.parent.mkdir(parents=True, exist_ok=True)
        path.write_text(json.dumps(self.to_dict(), indent=2), encoding="utf-8")

    @classmethod
    def load(cls, path: str | Path) -> "Phylactery":
        data = json.loads(Path(path).read_text(encoding="utf-8"))
        return cls.from_dict(data)

    @property
    def head(self) -> str:
        return self.chain[-1].hash

    @property
    def doctrine(self) -> str:
        return self.chain[-1].content

    def commit(self, content: str) -> str:
        new = PhylacteryCommit(content=content, parent_hash=self.head)
        self.chain.append(new)
        return new.hash

    def verify_chain(self) -> bool:
        """Verify the entire chain is untampered."""
        for i, commit in enumerate(self.chain):
            expected_parent = "" if i == 0 else self.chain[i - 1].hash
            if commit.parent_hash != expected_parent:
                return False
            expected_hash = hashlib.sha256(
                (commit.parent_hash + commit.content).encode()
            ).hexdigest()
            if commit.hash != expected_hash:
                return False
        return True

    def kappa(self, other_head: str) -> float:
        """Continuity metric: 1.0 if heads match, 0.0 otherwise.
        A real implementation would use vector divergence over doctrine fields."""
        return 1.0 if self.head == other_head else 0.0

    def __len__(self):
        return len(self.chain)

"""
MYELIN — Path-Dependent Graph Memory.

Sparse graph with bundled edge signals, strata-based decay,
and hardening through successful retrieval.

Specs: MYELIN_GRAPH_MEMORY, MYELIN_EDGE_BUNDLES, MYELIN_SPATIAL_STABILIZATION
"""

import time
from dataclasses import dataclass, field
from enum import Enum


class Stratum(Enum):
    CANONICAL = "canonical"
    OPERATIONAL = "operational"
    EPISODIC = "episodic"
    SPECULATIVE = "speculative"


STRATUM_DECAY = {
    Stratum.CANONICAL: 0.0,
    Stratum.OPERATIONAL: 0.01,
    Stratum.EPISODIC: 0.05,
    Stratum.SPECULATIVE: 0.2,
}


@dataclass
class MemoryNode:
    id: str
    content: str
    stratum: Stratum = Stratum.EPISODIC
    embedding: list[float] = field(default_factory=list)
    created_at: float = field(default_factory=time.time)
    access_count: int = 0
    retrieval_count: int = 0
    last_retrieved_at: float | None = None


@dataclass
class EdgeBundle:
    """Bundled relationship between two memory nodes."""
    source: str
    target: str
    semantic: float = 0.0       # s_ij: semantic similarity
    coactivation: int = 0       # c_ij: co-retrieval count
    retrieval_util: float = 0.5 # q_ij: retrieval utility
    staleness: float = 0.0      # δ_ij: time since last access

    def harden(self, reward: float, lam: float = 0.1):
        """q(t+1) = (1-λ)*q(t) + λ*r"""
        self.retrieval_util = (1 - lam) * self.retrieval_util + lam * reward
        if reward > 0:
            self.coactivation += 1
            self.staleness = 0.0

    def decay(self, dt: float, rate: float):
        """Apply time-based decay to staleness."""
        self.staleness += dt * rate


class MemoryGraph:
    """Sparse path-dependent memory graph."""

    def __init__(self):
        self.nodes: dict[str, MemoryNode] = {}
        self.edges: dict[tuple[str, str], EdgeBundle] = {}

    def add_node(self, id: str, content: str, stratum: Stratum = Stratum.EPISODIC,
                 embedding: list[float] | None = None) -> MemoryNode:
        node = MemoryNode(id=id, content=content, stratum=stratum,
                          embedding=embedding or [])
        self.nodes[id] = node
        return node

    def add_edge(self, source: str, target: str, semantic: float = 0.0) -> EdgeBundle:
        edge = EdgeBundle(source=source, target=target, semantic=semantic)
        self.edges[(source, target)] = edge
        return edge

    def retrieve(self, node_id: str) -> MemoryNode | None:
        """Retrieve a node and record access."""
        node = self.nodes.get(node_id)
        if node:
            node.access_count += 1
            node.retrieval_count += 1
            node.last_retrieved_at = time.time()
        return node

    def harden_path(self, path: list[str], reward: float = 1.0):
        """Harden all edges along a retrieval path."""
        for i in range(len(path) - 1):
            key = (path[i], path[i + 1])
            if key in self.edges:
                self.edges[key].harden(reward)

    def apply_decay(self, dt: float = 1.0):
        """Apply stratum-based decay to all edges."""
        for (src, _), edge in self.edges.items():
            src_node = self.nodes.get(src)
            if src_node:
                rate = STRATUM_DECAY.get(src_node.stratum, 0.05)
                edge.decay(dt, rate)

    def neighbors(self, node_id: str) -> list[tuple[str, EdgeBundle]]:
        """Get all neighbors of a node with their edge bundles."""
        result = []
        for (src, tgt), edge in self.edges.items():
            if src == node_id:
                result.append((tgt, edge))
            elif tgt == node_id:
                result.append((src, edge))
        return result

    @property
    def node_count(self) -> int:
        return len(self.nodes)

    @property
    def edge_count(self) -> int:
        return len(self.edges)

