            identity_kernel={"name": "OmegA", "doctrine": "test"},
            goal_contract="initial task",
            version=self.clock.next(),
        )
        self.goal = GoalContract(task="test task")
        self.budget = ClaimBudget()
        self.memory = MemoryGraph()
        self.risk_gate = RiskGate()

